<script setup lang="ts">import type { BpmBusinessObjectTechnicalDetail } from '#/api/system/bpm';import { onMounted,ref } from 'vue';import { ElButton,ElCollapse,ElCollapseItem,ElInput,ElInputNumber,ElTag } from 'element-plus';import { diffBpmBusinessObjectTechnicalDetail,getBpmBusinessObjectTechnicalDetail } from '#/api/system/bpm';const props=defineProps<{contractKey:string;contractVersion:number}>();const detail=ref<BpmBusinessObjectTechnicalDetail>();const compareVersion=ref(Math.max(1,props.contractVersion-1));const changed=ref<string[]>([]);onMounted(async()=>detail.value=await getBpmBusinessObjectTechnicalDetail(props.contractKey,props.contractVersion));async function compare(){changed.value=(await diffBpmBusinessObjectTechnicalDetail(props.contractKey,compareVersion.value,props.contractVersion)).changedFieldKeys}</script>
<template><ElCollapse v-if="detail"><ElCollapseItem title="技术协议（只读）"><div class="meta"><ElTag>Schema v{{detail.schemaVersion}}</ElTag><span>摘要：{{detail.digest}}</span></div><div class="compare"><ElInputNumber v-model="compareVersion" :min="1"/><ElButton @click="compare">版本对比</ElButton><ElTag v-for="key in changed" :key="key" effect="plain">{{key}}</ElTag></div><ElInput :model-value="detail.canonicalPayload" :rows="14" readonly type="textarea"/></ElCollapseItem></ElCollapse></template><style scoped>.meta,.compare{display:flex;align-items:center;flex-wrap:wrap;gap:8px;margin-bottom:12px}.meta span{color:var(--el-text-color-secondary);overflow-wrap:anywhere}</style>
